import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import axios from 'axios';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import ProductDetail from './pages/ProductDetail';
import GenderCategory from './pages/GenderCategory';
import Cart from './pages/Cart';
import Checkout from './pages/Checkout';
import Profile from './pages/Profile';
import OrderHistory from './pages/OrderHistory';
import Wishlist from './pages/Wishlist';
import ImageAnalyzer from './pages/ImageAnalyzer';
import './App.css';

// Inner component that uses useLocation (must be inside Router)
function AppContent({ user, token, handleLogin, onLogout, onGenderClick, showSidebar, sidebarGender, setShowSidebar }) {
  return (
    <>
      <Navbar user={user} token={token} onLogout={onLogout} onGenderClick={onGenderClick} />
      <Sidebar showSidebar={showSidebar} sidebarGender={sidebarGender} setShowSidebar={setShowSidebar} />
      <div className="container">
        <Routes>
          <Route path="/" element={<Home showSidebar={showSidebar} sidebarGender={sidebarGender} setShowSidebar={setShowSidebar} setSidebarGender={() => {}} />} />
          <Route path="/:gender" element={<GenderCategory />} />
          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register onLogin={handleLogin} />} />
          <Route path="/product/:id" element={<ProductDetail token={token} />} />
          <Route path="/ai-finder" element={<ImageAnalyzer />} />
          <Route path="/cart" element={token ? <Cart token={token} /> : <Navigate to="/login" />} />
          <Route path="/wishlist" element={token ? <Wishlist token={token} /> : <Navigate to="/login" />} />
          <Route path="/checkout" element={token ? <Checkout token={token} /> : <Navigate to="/login" />} />
          <Route path="/profile" element={token ? <Profile token={token} user={user} /> : <Navigate to="/login" />} />
          <Route path="/orders" element={token ? <OrderHistory token={token} /> : <Navigate to="/login" />} />
        </Routes>
      </div>
    </>
  );
}

function App() {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [showSidebar, setShowSidebar] = useState(false);
  const [sidebarGender, setSidebarGender] = useState('');

  useEffect(() => {
    if (token) {
      // Verify token
      axios.get('/api/auth/me', {
        headers: { Authorization: `Bearer ${token}` }
      })
      .then(res => setUser(res.data))
      .catch(err => {
        localStorage.removeItem('token');
        setToken(null);
      });
    }
  }, [token]);

  const handleLogin = (newToken) => {
    setToken(newToken);
    localStorage.setItem('token', newToken);
  };

  const handleLogout = () => {
    setToken(null);
    localStorage.removeItem('token');
    setUser(null);
  };

  const handleGenderClick = (gender) => {
    setSidebarGender(gender);
    setShowSidebar(true);
  };

  return (
    <Router>
      <AppContent
        user={user}
        token={token}
        handleLogin={handleLogin}
        onLogout={handleLogout}
        onGenderClick={handleGenderClick}
        showSidebar={showSidebar}
        sidebarGender={sidebarGender}
        setShowSidebar={setShowSidebar}
      />
    </Router>
  );
}

export default App;
